import React, { useState } from "react";
import axios from "axios";

function App() {
  const [title, setTitle] = useState("");
  const [description, setDescription] = useState("");
  const [msg, setMsg] = useState("");

  const addJob = async () => {
  try {
    await axios.post("http://127.0.0.1:8000/job", {
      title: title,
      description: description
    });

    setMsg("Job Added Successfully");
  } catch (error) {
    console.log(error);
    setMsg("Error adding job");
  }
};

  return (
    <div style={{
      padding:"40px",
      fontFamily:"Arial",
      background:"#0f172a",
      color:"white",
      minHeight:"100vh"
    }}>
      <h1>ResumeX AI</h1>
      <p>Smart Resume Screening & Job Matching System</p>

      <div style={{marginTop:"30px"}}>
        <input
          placeholder="Job Title"
          value={title}
          onChange={(e)=>setTitle(e.target.value)}
          style={input}
        /><br/><br/>

        <textarea
          placeholder="Job Description"
          value={description}
          onChange={(e)=>setDescription(e.target.value)}
          style={{...input,height:"100px"}}
        /><br/><br/>

        <button style={btn} onClick={addJob}>Add Job</button>
        <p>{msg}</p>
      </div>
    </div>
  );
}

const input = {
  padding:"10px",
  width:"300px",
  borderRadius:"8px"
};

const btn = {
  padding:"12px 20px",
  border:"none",
  borderRadius:"8px",
  cursor:"pointer"
};

export default App;
